// コラージュテンプレートで使う花のイラスト素材（透過PNG）を
// base64データURLとして直接埋め込む。require()経由のアセット解決は
// バンドラー設定によってWeb上でURIが正しく解決されないことがあり、
// 花が表示されない不具合が起きたため、確実に読み込めるこの形にした。

export const FLOWER_CORNER_TL = 'data:image/png;base64,';

export const FLOWER_CORNER_TR = 'data:image/png;base64,';

export const FLOWER_FRAME_BORDER = 'data:image/png;base64,';

export const FLOWER_CLUSTER = 'data:image/png;base64,';
